const pnid = $('Trigger - Execute Workflow').first().json.phone_number_id;
const item = $input.first();

if (item.error) {
  throw new Error('Error al contactar Django para phone_number_id: ' + pnid);
}

const data = item.json;

if (data.detail || data.error) {
  throw new Error('Error de Django para phone_number_id: ' + pnid + '. Detalle: ' + (data.detail || data.error));
}

const required = ['clinic_id', 'agent_api_key', 'whatsapp_phone_number_id', 'whatsapp_token'];
const missing = required.filter(function(f) { return !data[f]; });

if (missing.length > 0) {
  throw new Error('Config incompleta para phone_number_id: ' + pnid + '. Campos faltantes: ' + missing.join(', '));
}

return [{ json: data }];

const data = $input.first().json;
const result = Object.assign({}, data, {
  django_auth_header: 'Api-Key ' + data.agent_api_key,
  whatsapp_api_url: $env.WHATSAPP_API_URL || ''
});
return [{ json: result }];
